import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card";
import {
  Activity,
  Users,
  FileText,
  Calendar,
  ArrowRight,
  CheckCircle,
  Clock,
} from "lucide-react";
import { createClient } from "@/lib/supabase/server";
import Link from "next/link";
import { format, parseISO } from "date-fns";
import { fr } from "date-fns/locale";

export default async function AdminDashboardPage() {
  const supabase = await createClient();

  // 1. Total Patients
  const { count: totalPatients } = await supabase
    .from("patients")
    .select("*", { count: "exact", head: true });

  // 2. Upcoming Appointments (Today onwards)
  const todayISO = new Date().toISOString();
  const { count: upcomingAppointments } = await supabase
    .from("appointments")
    .select("*", { count: "exact", head: true })
    .gte("appointment_date", todayISO)
    .neq("status", "cancelled");

  // 3. Treatments recorded this month
  const startOfMonth = new Date();
  startOfMonth.setDate(1);
  startOfMonth.setHours(0, 0, 0, 0);
  const { count: treatmentsThisMonth } = await supabase
    .from("odontogram_records")
    .select("*", { count: "exact", head: true })
    .gte("date_recorded", startOfMonth.toISOString());

  // 4. Pending Invoices
  const { count: pendingInvoices } = await supabase
    .from("invoices")
    .select("*", { count: "exact", head: true })
    .eq("status", "pending");

  // 5. Recent Patients
  const { data: recentPatients } = await supabase
    .from("patients")
    .select("id, first_name, last_name, patient_number, created_at")
    .order("created_at", { ascending: false })
    .limit(5);

  // 6. Recent Invoices (Activity)
  const { data: recentInvoices } = await supabase
    .from("invoices")
    .select(
      `
      id, 
      total_amount, 
      status, 
      created_at, 
      patients (
        first_name, 
        last_name
      )
    `,
    )
    .order("created_at", { ascending: false })
    .limit(5);

  const formatCurrency = (amount: number) => {
    return new Intl.NumberFormat("fr-SN", {
      style: "currency",
      currency: "XOF",
    }).format(amount);
  };

  return (
    <div className="space-y-6">
      <div>
        <h1 className="text-3xl font-bold tracking-tight">Tableau de Bord</h1>
        <p className="text-muted-foreground mt-2">
          Aperçu de l&apos;activité de la clinique dentaire DABIA.
        </p>
      </div>

      <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-4">
        <Card>
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">
              Patients Totaux
            </CardTitle>
            <Users className="h-4 w-4 text-muted-foreground" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">{totalPatients || 0}</div>
            <p className="text-xs text-muted-foreground">
              Base de données complète
            </p>
          </CardContent>
        </Card>
        <Card>
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">
              Rendez-vous à venir
            </CardTitle>
            <Calendar className="h-4 w-4 text-muted-foreground" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">
              {upcomingAppointments || 0}
            </div>
            <p className="text-xs text-muted-foreground">Planifiés</p>
          </CardContent>
        </Card>
        <Card>
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">
              Soins enregistrés
            </CardTitle>
            <Activity className="h-4 w-4 text-muted-foreground" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">{treatmentsThisMonth || 0}</div>
            <p className="text-xs text-muted-foreground">
              Depuis de début du mois
            </p>
          </CardContent>
        </Card>
        <Card>
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">
              Factures en attente
            </CardTitle>
            <FileText className="h-4 w-4 text-muted-foreground" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">{pendingInvoices || 0}</div>
            <p className="text-xs text-muted-foreground">Reste à recouvrer</p>
          </CardContent>
        </Card>
      </div>

      <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-7">
        <Card className="col-span-4 flex flex-col">
          <CardHeader>
            <CardTitle>Activité Financière Récente</CardTitle>
            <CardDescription>
              Aperçu des 5 dernières factures générées.
            </CardDescription>
          </CardHeader>
          <CardContent className="flex-1">
            <div className="space-y-4">
              {recentInvoices && recentInvoices.length > 0 ? (
                recentInvoices.map(
                  // eslint-disable-next-line @typescript-eslint/no-explicit-any
                  (inv: any) => (
                    <div
                      key={inv.id}
                      className="flex items-center justify-between border-b pb-2 last:border-0 last:pb-0"
                    >
                      <div className="space-y-1">
                        <p className="text-sm font-medium leading-none">
                          {inv.patients?.first_name} {inv.patients?.last_name}
                        </p>
                        <p className="text-xs text-muted-foreground">
                          {format(
                            parseISO(inv.created_at),
                            "dd MMM yyyy à HH:mm",
                            { locale: fr },
                          )}
                        </p>
                      </div>
                      <div className="flex items-center gap-4">
                        <div className="text-sm font-medium">
                          {formatCurrency(inv.total_amount)}
                        </div>
                        {inv.status === "paid" ? (
                          <CheckCircle className="w-4 h-4 text-green-500" />
                        ) : (
                          <Clock className="w-4 h-4 text-amber-500" />
                        )}
                      </div>
                    </div>
                  ),
                )
              ) : (
                <p className="text-sm text-muted-foreground text-center py-4">
                  Aucune activité récente.
                </p>
              )}
            </div>
          </CardContent>
        </Card>
        <Card className="col-span-3 flex flex-col">
          <CardHeader>
            <CardTitle>Derniers Patients Inscrits</CardTitle>
            <CardDescription>
              Les 5 derniers dossiers créés ou importés.
            </CardDescription>
          </CardHeader>
          <CardContent className="flex-1">
            <div className="space-y-4">
              {recentPatients && recentPatients.length > 0 ? (
                recentPatients.map((patient) => (
                  <div
                    key={patient.id}
                    className="flex items-center justify-between border-b pb-2 last:border-0 last:pb-0"
                  >
                    <div className="space-y-1">
                      <p className="text-sm font-medium leading-none">
                        {patient.first_name} {patient.last_name}
                      </p>
                      <p className="text-xs text-muted-foreground">
                        N° {patient.patient_number}
                      </p>
                    </div>
                    <Link
                      href={`/admin/patients/${patient.id}`}
                      className="text-muted-foreground hover:text-primary transition-colors"
                    >
                      <ArrowRight className="h-4 w-4" />
                    </Link>
                  </div>
                ))
              ) : (
                <p className="text-sm text-muted-foreground text-center py-4">
                  Aucun patient récent.
                </p>
              )}
            </div>
          </CardContent>
        </Card>
      </div>
    </div>
  );
}
